const staticData = $getWorkflowStaticData('global');
if (!staticData.messageBuffer) {
  staticData.messageBuffer = {};
}

const key = $json.sessionId || `campana:${$json.celular}`;
const now = Date.now();
const mergeWindowMs = 10000;
const staleWindowMs = 120000;

const entry = staticData.messageBuffer[key] || {
  messages: [],
  latestToken: null,
  updatedAt: 0,
};

if (now - entry.updatedAt > staleWindowMs) {
  entry.messages = [];
}

const isVoice = $json.isVoice === true;
const text = String($json.mensaje || '').trim();

if (isVoice || text) {
  entry.messages.push({
    type: isVoice ? 'voice' : 'text',
    text: isVoice ? '' : text,
    ts: now,
    messageId: $json.messageId || '',
    mimeType: $json.audioMimeType || '',
    isPtt: $json.isPtt === true,
  });
}

entry.messages = entry.messages.filter((message) => now - message.ts <= mergeWindowMs);
entry.updatedAt = now;
entry.latestToken = `${now}-${Math.random().toString(36).slice(2, 10)}`;
staticData.messageBuffer[key] = entry;

return [{
  json: {
    ...$json,
    batch_token: entry.latestToken,
    batch_window_ms: mergeWindowMs,
  },
}];

const staticData = $getWorkflowStaticData('global');
const key = $json.sessionId || `campana:${$json.celular}`;
const entry = staticData.messageBuffer?.[key];

if (!entry || entry.latestToken !== $json.batch_token) {
  return [{ json: { ...$json, should_process_batch: false } }];
}

const messages = (entry.messages || []).slice().sort((a, b) => a.ts - b.ts);
const textMessages = messages.filter((message) => message.type === 'text');
const voiceMessages = messages.filter((message) => message.type === 'voice' && message.messageId);
const latestVoice = voiceMessages.length ? voiceMessages[voiceMessages.length - 1] : null;
const mergedText = textMessages
  .map((message) => String(message.text || '').trim())
  .filter(Boolean)
  .join(' ')
  .replace(/\s+/g, ' ')
  .trim();

delete staticData.messageBuffer[key];

return [{
  json: {
    ...$json,
    mensaje: mergedText,
    should_process_batch: true,
    has_voice: voiceMessages.length > 0,
    is_voice_only: voiceMessages.length > 0 && !mergedText,
    audio_message_id: latestVoice?.messageId || '',
    audio_mime_type: latestVoice?.mimeType || $json.audioMimeType || 'audio/ogg; codecs=opus',
    audio_is_ptt: latestVoice?.isPtt === true,
    batch_size: messages.length,
  },
}];

const input = $input.first().json;
const output = String(input.output || '');

const shouldEscalate = output.includes('##DERIVAR_A_HUMANO##');
const shouldRegister = output.includes('##REGISTRAR_LEAD##');

const textoLimpio = output
  .replace(/##DERIVAR_A_HUMANO##/g, '')
  .replace(/##REGISTRAR_LEAD##/g, '')
  .trim() || 'Gracias por tu mensaje. ¿Te gustaría que te cuente una propuesta concreta de Pedro Halley para jubilados?';

const base = Math.floor(Math.random() * (8000 - 2500) + 2500);
const typing = textoLimpio.length * 38;
const delayMs = Math.min(base + typing, 18000);
const delayS = Math.max(1, Math.ceil(delayMs / 1000));

return [{
  json: {
    celular: input.celular ?? $('Set Fields').item.json.celular,
    mensaje: input.mensaje ?? $('Set Fields').item.json.mensaje,
    respuesta_texto: textoLimpio,
    delay_ms: delayMs,
    delay_s: delayS,
    should_escalate: shouldEscalate,
    should_register: shouldRegister,
  },
}];

const delayMs = 2500;

return [{
  json: {
    celular: $json.celular ?? $('Resolve Batch').item.json.celular,
    mensaje: $json.mensaje ?? $('Resolve Batch').item.json.mensaje ?? '[audio]',
    respuesta_texto: 'Entiendo tu mensaje. Si querés, te cuento propuestas concretas de Pedro Halley para jubilados y adultos mayores.',
    delay_ms: delayMs,
    delay_s: Math.max(1, Math.ceil(delayMs / 1000)),
    should_escalate: false,
    should_register: false,
  },
}];

