const batch = $('Resolve Batch').item.json;
const response = $input.first().json || {};
const rawBase64 = response.base64 || response.data?.base64 || response.response?.base64 || '';
const cleanBase64 = String(rawBase64).replace(/^data:.*?;base64,/, '').trim();
const mimeType = response.mimetype || response.mimeType || batch.audio_mime_type || 'audio/ogg; codecs=opus';
const extensionMap = {
  'audio/ogg': 'ogg',
  'audio/ogg; codecs=opus': 'ogg',
  'audio/opus': 'opus',
  'audio/mpeg': 'mp3',
  'audio/mp3': 'mp3',
  'audio/mp4': 'mp4',
  'audio/aac': 'aac',
  'audio/wav': 'wav',
  'audio/x-wav': 'wav',
  'audio/webm': 'webm',
};
const normalizedMimeType = String(mimeType).split(';')[0].trim() || 'audio/ogg';
const extension = extensionMap[String(mimeType).trim()] || extensionMap[normalizedMimeType] || 'ogg';

const item = {
  json: {
    ...batch,
    stt_ready: Boolean(cleanBase64),
    stt_provider: 'openai-whisper',
    stt_source_mime_type: mimeType,
  },
};

if (cleanBase64) {
  item.binary = {
    data: {
      data: cleanBase64,
      mimeType: normalizedMimeType,
      fileName: `audio-${batch.audio_message_id || Date.now()}.${extension}`,
      fileExtension: extension,
    },
  };
}

return [item];

const batch = $('Resolve Batch').item.json;
const prepared = $('Preparar Audio Binary').item.json;
const response = $input.first().json || {};

const rawTranscript = response.text || response.transcription || response.output_text || response.data?.text || '';
const transcript = String(rawTranscript || '').replace(/\s+/g, ' ').trim();
const baseText = String(batch.mensaje || '').replace(/\s+/g, ' ').trim();
const shouldUseAi = Boolean(baseText || transcript);
const mergedPrompt = [baseText, transcript].filter(Boolean).join(' ').replace(/\s+/g, ' ').trim();

return [{
  json: {
    ...batch,
    mensaje: mergedPrompt,
    texto_transcrito: transcript,
    stt_ok: Boolean(transcript),
    stt_ready: prepared.stt_ready === true,
    should_use_ai: shouldUseAi,
    stt_provider: prepared.stt_provider || 'openai-whisper',
    stt_error: response.error?.message || response.message || (!prepared.stt_ready ? 'audio_base64_missing' : ''),
  },
}];
